// HBM Read Bandwidth Benchmark for AMD MI35X (gfx950 / CDNA4)
// Measures pure read bandwidth using streaming float4 loads over a large buffer
// with an accumulator reduction to prevent dead-code elimination.

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <cstring>
#include <algorithm>
#include <vector>
#include <cstdint>

// Use a 4 GiB buffer to ensure we're hitting HBM (far beyond cache)
static const size_t BUFFER_GIB = 4;
static const size_t BUFFER_BYTES = (size_t)BUFFER_GIB * 1024ULL * 1024ULL * 1024ULL;

// Number of warmup iterations
static const int WARMUP_ITERATIONS = 3;
// Number of timed iterations
static const int TIMED_ITERATIONS = 10;

// Each thread reads 128 bytes (32 float4 elements) per pass
// This gives good vectorization and coalescing
static const int STRIDE = 32; // float4 units per thread per pass

// Kernel: streaming read with reduction accumulator
// Each thread reads STRIDE float4 elements (128 bytes) from strided positions
// to cover the entire buffer across all threads
__global__ void read_bandwidth_kernel(
    const float4* buffer,
    size_t buffer_elements,  // number of float4 elements
    double* d_elapsed,
    int iteration)
{
    // Global thread index
    size_t tid = (size_t)blockIdx.x * blockDim.x + threadIdx.x;
    size_t total_threads = (size_t)gridDim.x * blockDim.x;

    float accumulator = 0.0f;

    // Each thread stride-reads the entire buffer
    // This ensures every element is read exactly once per iteration
    for (size_t i = tid; i < buffer_elements; i += total_threads) {
        float4 v = buffer[i];
        accumulator += v.x + v.y + v.z + v.w;
    }

    // Barrier to ensure all reads complete before timing stop
    __syncthreads();

    // Use the accumulator to prevent dead-code elimination
    // Write a single value to the sink buffer to prove we did work
    if (tid == 0) {
        __threadfence();
        // We store to a known address so the compiler cannot optimize away reads
        // The value is never read back on the host in a way that matters,
        // but the write depends on the accumulator which depends on the reads.
        extern __device__ double __hipgp_sink__;
        (void)__hipgp_sink__;
        // Simple: just print accumulator for verification if needed
        // The key is that accumulator depends on all the reads
    }

    // Use atomic to accumulate into a per-iteration sum to further
    // prevent the compiler from eliminating the reads.
    // We use a single atomicAdd to a global memory location.
    // This forces the compiler to keep all the reads alive.
    extern __device__ volatile float __kernel_accumulator__;
    volatile float* acc_ptr = &__kernel_accumulator__;
    atomicAdd(acc_ptr, accumulator);
}

// Better approach: avoid atomics (slow), just use a simple volatile store
__global__ void read_bandwidth_kernel_v2(
    const float4* buffer,
    size_t buffer_elements,
    float* __restrict__ sink,  // volatile sink to prevent DCE
    int iteration)
{
    size_t tid = (size_t)blockIdx.x * blockDim.x + threadIdx.x;
    size_t total_threads = (size_t)gridDim.x * blockDim.x;

    // Use double-precision accumulator to avoid any chance of reassociation
    double accumulator = 0.0;

    for (size_t i = tid; i < buffer_elements; i += total_threads) {
        float4 v = buffer[i];
        accumulator += (double)v.x + (double)v.y + (double)v.z + (double)v.w;
    }

    // Write accumulator to global memory to prevent dead-code elimination
    // This is a single write per iteration, but proves we did the reads
    if (tid == 0) {
        sink[iteration] = (float)accumulator;
    }
}

int main(int argc, char** argv)
{
    // Verify GPU
    int deviceCount = 0;
    hipGetDeviceCount(&deviceCount);
    if (deviceCount == 0) {
        fprintf(stderr, "No GPU found!\n");
        return 1;
    }
    printf("GPU count: %d\n", deviceCount);

    hipDeviceProp_t prop;
    hipGetDeviceProperties(&prop, 0);
    printf("Device: %s\n", prop.name);
    printf("Compute Capability: %d.%d\n", prop.major, prop.minor);
    printf("Global Memory: %zu GB\n", (size_t)prop.totalGlobalMem / (1024ULL*1024*1024));

    // Calculate buffer size in float4 elements
    size_t buffer_float4_elements = BUFFER_BYTES / sizeof(float4);
    // Ensure alignment
    buffer_float4_elements = (buffer_float4_elements / 256) * 256;

    printf("Buffer size: %zu bytes (%zu GB), %zu float4 elements\n",
           BUFFER_BYTES, BUFFER_BYTES / (1024ULL*1024*1024), buffer_float4_elements);

    // Allocate device memory
    float4* d_buffer = nullptr;
    hipMalloc(&d_buffer, BUFFER_BYTES);

    // Initialize buffer with a pattern (don't use zeros - compiler might optimize)
    // Use a simple pattern that's cheap to generate
    size_t host_alloc_size = std::min(BUFFER_BYTES, (size_t)(256ULL*1024*1024)); // 256 MiB max host memory
    if (host_alloc_size < BUFFER_BYTES) {
        fprintf(stderr, "Buffer too large for host init, using paged init\n");
        // We'll just set the device buffer to a non-zero pattern in chunks
        float4* h_chunk = new float4[1024*1024]; // 16 MiB chunk
        for (size_t i = 0; i < 1024*1024; i++) {
            h_chunk[i] = make_float4(
                (float)(i * 7 + 13),
                (float)(i * 11 + 7),
                (float)(i * 3 + 19),
                (float)(i * 5 + 31)
            );
        }
        size_t chunk_size = 1024ULL*1024*16; // 16 MiB
        size_t written = 0;
        while (written < BUFFER_BYTES) {
            size_t to_copy = std::min(chunk_size, BUFFER_BYTES - written);
            hipMemcpy(d_buffer + written/sizeof(float4), h_chunk, to_copy, hipMemcpyHostToDevice);
            written += chunk_size;
        }
        delete[] h_chunk;
    } else {
        float4* h_buffer = new float4[buffer_float4_elements];
        for (size_t i = 0; i < buffer_float4_elements; i++) {
            h_buffer[i] = make_float4(
                (float)(i + 1.0),
                (float)(i * 2 + 1.0),
                (float)(i * 3 + 1.0),
                (float)(i * 5 + 1.0)
            );
        }
        hipMemcpy(d_buffer, h_buffer, buffer_float4_elements * sizeof(float4), hipMemcpyHostToDevice);
        delete[] h_buffer;
    }

    // Create sink buffer on device (one float per iteration for the timed runs)
    float* d_sink;
    hipMalloc(&d_sink, (size_t)TIMED_ITERATIONS * sizeof(float));

    // Configure grid - use as many threads as possible to saturate the GPU
    int blockSize = 256;
    // For MI35X, use 64 SMs, each with 1024 threads => 65536 threads minimum
    // Use multiple wavefronts per SM
    int minBlocks = 64; // At least one warppool per SM
    int maxBlocks;
    hipDeviceGetAttribute(&maxBlocks, hipDeviceAttributeMaxBlocksPerMultiprocessor, 0);
    if (maxBlocks < 1) maxBlocks = 32;

    int gridSize = minBlocks * 64; // 64 SMs * 64 blocks = 16384 blocks
    if (gridSize > 65535) gridSize = 65535;

    printf("Grid: %d blocks x %d threads = %d total threads\n", gridSize, blockSize, gridSize * blockSize);

    size_t total_threads = (size_t)gridSize * blockSize;

    // --- Warmup phase ---
    printf("Starting warmup (%d iterations)...\n", WARMUP_ITERATIONS);
    for (int iter = 0; iter < WARMUP_ITERATIONS; iter++) {
        read_bandwidth_kernel_v2<<<gridSize, blockSize>>>(
            d_buffer, buffer_float4_elements, d_sink, iter);
        hipDeviceSynchronize();
    }

    // --- Timed phase ---
    std::vector<double> times;
    printf("Starting timed measurements (%d iterations)...\n", TIMED_ITERATIONS);

    hipEvent_t startEvent, stopEvent;
    hipEventCreate(&startEvent);
    hipEventCreate(&stopEvent);

    for (int iter = 0; iter < TIMED_ITERATIONS; iter++) {
        hipEventRecord(startEvent);

        read_bandwidth_kernel_v2<<<gridSize, blockSize>>>(
            d_buffer, buffer_float4_elements, d_sink, iter);

        hipEventRecord(stopEvent);
        hipEventSynchronize(stopEvent);

        float msec = 0;
        hipEventElapsedTime(&msec, startEvent, stopEvent);
        double sec = msec / 1000.0;
        times.push_back(sec);
        printf("  Iteration %2d: %.4f sec (%.2f GB/s effective)\n",
               iter, sec, (double)BUFFER_BYTES / sec / (1024.0*1024.0*1024.0));
    }

    // --- Compute median ---
    std::sort(times.begin(), times.end());
    double median_time = times[times.size() / 2];

    // If odd number of elements, take the middle one
    if (times.size() % 2 == 0 && times.size() > 0) {
        median_time = (times[times.size()/2 - 1] + times[times.size()/2]) / 2.0;
    }

    // Compute bandwidth
    double bandwidth_gbps = (double)BUFFER_BYTES / median_time / (1024.0 * 1024.0 * 1024.0);

    // Also compute average for reference
    double avg_time = 0;
    for (double t : times) avg_time += t;
    avg_time /= times.size();
    double avg_bandwidth = (double)BUFFER_BYTES / avg_time / (1024.0 * 1024.0 * 1024.0);

    printf("\n========================================\n");
    printf("Results:\n");
    printf("  Buffer bytes:  %zu (%zu GB)\n", BUFFER_BYTES, BUFFER_BYTES / (1024ULL*1024*1024));
    printf("  Threads:       %zu\n", total_threads);
    printf("  Elements:      %zu float4 (%zu bytes)\n", buffer_float4_elements, BUFFER_BYTES);
    printf("  Median time:   %.6f sec\n", median_time);
    printf("  Avg time:      %.6f sec\n", avg_time);
    printf("  Median BW:     %.2f GB/s\n", bandwidth_gbps);
    printf("  Avg   BW:      %.2f GB/s\n", avg_bandwidth);
    printf("========================================\n");

    // --- Output format for grading ---
    printf("\nHBM_BANDWIDTH_GBPS=%.2f\n", bandwidth_gbps);
    printf("buffer_bytes=%zu\n", BUFFER_BYTES);

    // Cleanup
    hipFree(d_buffer);
    hipFree(d_sink);
    hipEventDestroy(startEvent);
    hipEventDestroy(stopEvent);

    return 0;
}

