// HBM Read Bandwidth Microbenchmark for AMD MI35X (gfx950)
// Pure read streaming pass over a 4 GiB buffer with per-thread accumulation
// via atomicAdd so that EVERY thread's reads are proven live (prevents DCE).

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

// --- Configuration ---
#define WORKSET_GIB       4
#define WARMUP_ITERS      3
#define TIMED_ITERS       15
#define BLOCK_SIZE        256

// Each thread writes to its own entry in d_acc[] so the compiler cannot
// eliminate any read. The entire buffer must be streamed to produce the
// per-thread accumulators.
__global__ void stream_read_kernel(const float4* buf, size_t n_float4,
                                   float* d_acc, float* d_global_sum)
{
    size_t tid = (size_t)blockIdx.x * (size_t)blockDim.x + (size_t)threadIdx.x;
    size_t nblk = (size_t)gridDim.x * (size_t)blockDim.x;

    float acc = 0.0f;
    // Grid-stride loop: read all buffer elements assigned to this thread
    for (size_t i = tid; i < n_float4; i += nblk) {
        float4 v = buf[i];
        acc += v.x + v.y + v.z + v.w;
    }

    // Every thread atomically stores its accumulator at a unique index,
    // so the compiler cannot eliminate any read -- every float4 access
    // feeds into a distinct atomic store.
    size_t idx = tid & 0xFFFFF;          // up to 1M unique slots per block grid
    atomicAdd(&d_acc[idx], acc);
}

int main()
{
    int dev = 0;
    hipSetDevice(dev);

    hipDeviceProp_t prop;
    hipGetDeviceProperties(&prop, dev);
    printf("Device: %s  arch: %s  VRAM: %.0f GB  SMs: %d\n",
           prop.name, prop.gcnArchName,
           (double)prop.totalGlobalMem / (1024.0*1024*1024),
           prop.multiProcessorCount);

    size_t workset_bytes = (size_t)WORKSET_GIB * 1024ULL * 1024ULL * 1024ULL;
    size_t n_float4 = workset_bytes / sizeof(float4);
    printf("Working set: %zu bytes (%d GB), %zu float4 elements\n",
           workset_bytes, WORKSET_GIB, n_float4);

    /* ---- device allocation ---- */
    float4* d_buf = nullptr;
    hipMalloc(&d_buf, workset_bytes);

    // d_acc: each thread contributes to one slot; need enough slots
    // We want each thread to have a unique slot when possible.
    // Max grid = 2^31, so we use modular indexing with a large count.
    // 1M slots should be enough for any reasonable grid.
    size_t n_acc_slots = 1024 * 1024;
    float* d_acc;
    hipMalloc(&d_acc, n_acc_slots * sizeof(float));

    float* d_global_sum;
    hipMalloc(&d_global_sum, sizeof(float));
    hipMemset(d_global_sum, 0, sizeof(float));

    /* ---- fill buffer with a non-trivial pattern ---- */
    size_t chunk_sz = 64ULL * 1024 * 1024;   // 64 MiB
    float4* h_chunk = new float4[chunk_sz / sizeof(float4)];
    for (size_t j = 0; j < chunk_sz / sizeof(float4); j++) {
        h_chunk[j] = make_float4(
            (float)(j * 7 + 13),
            (float)(j * 11 + 7),
            (float)(j * 3 + 19),
            (float)(j * 5 + 31));
    }
    for (size_t offset = 0; offset < workset_bytes; offset += chunk_sz) {
        size_t sz = std::min(chunk_sz, workset_bytes - offset);
        hipMemcpy(d_buf + offset / sizeof(float4),
                  h_chunk, sz, hipMemcpyHostToDevice);
    }
    delete[] h_chunk;
    hipDeviceSynchronize();

    /* ---- configure grid ---- */
    int maxGridX;
    hipDeviceGetAttribute(&maxGridX, hipDeviceAttributeMaxGridDimX, dev);
    // Aim for num_threads ~ n_float4 so each thread reads ~1 element.
    // But clamp to maxGridX * BLOCK_SIZE.
    size_t target_threads = n_float4;
    if ((size_t)maxGridX * BLOCK_SIZE < target_threads)
        target_threads = (size_t)maxGridX * BLOCK_SIZE;
    // Also cap: don't exceed ~4x elements (each thread reads at most ceil(n/total))
    if (target_threads > n_float4 * 4)
        target_threads = n_float4 * 4;

    int gridSize = (int)(target_threads / BLOCK_SIZE);
    if (gridSize < 1) gridSize = 1;
    if (gridSize > maxGridX) gridSize = maxGridX;
    int num_threads = gridSize * BLOCK_SIZE;

    printf("Grid: %d blocks x %d threads = %d total\n",
           gridSize, BLOCK_SIZE, num_threads);
    printf("Read coverage: %.1f pass(es) per element\n",
           (double)num_threads / (double)n_float4);

    /* ---- warmup ---- */
    printf("Warming up (%d iters)...\n", WARMUP_ITERS);
    for (int w = 0; w < WARMUP_ITERS; w++) {
        hipMemset(d_acc, 0, n_acc_slots * sizeof(float));
        stream_read_kernel<<<gridSize, BLOCK_SIZE>>>(d_buf, n_float4, d_acc, d_global_sum);
        hipDeviceSynchronize();
    }

    /* ---- timed runs ---- */
    hipEvent_t startEv, stopEv;
    hipEventCreate(&startEv);
    hipEventCreate(&stopEv);

    std::vector<double> times_ms;
    times_ms.reserve(TIMED_ITERS);

    printf("Timing (%d iters)...\n", TIMED_ITERS);
    for (int i = 0; i < TIMED_ITERS; i++) {
        hipMemset(d_acc, 0, n_acc_slots * sizeof(float));
        hipEventRecord(startEv);
        stream_read_kernel<<<gridSize, BLOCK_SIZE>>>(d_buf, n_float4, d_acc, d_global_sum);
        hipEventRecord(stopEv);
        hipEventSynchronize(stopEv);

        float ms = 0;
        hipEventElapsedTime(&ms, startEv, stopEv);
        times_ms.push_back((double)ms);
        double bw = (double)workset_bytes / ((double)ms * 1e-3) / 1e9;
        printf("  [%2d] %.3f ms  ->  %.2f GB/s\n", i, ms, bw);
    }

    /* ---- median ---- */
    std::sort(times_ms.begin(), times_ms.end());
    int mid = (int)times_ms.size() / 2;
    double median_ms = times_ms[mid];
    double median_bw = (double)workset_bytes / (median_ms * 1e-3) / 1e9;

    printf("\n--- Median: %.3f ms  =>  %.2f GB/s ---\n", median_ms, median_bw);

    /* ---- output in required format ---- */
    printf("HBM_BANDWIDTH_GBPS=%.2f\n", median_bw);
    printf("buffer_bytes=%zu\n", workset_bytes);

    /* ---- cleanup ---- */
    hipFree(d_buf);
    hipFree(d_acc);
    hipFree(d_global_sum);
    hipEventDestroy(startEv);
    hipEventDestroy(stopEv);
    return 0;
}

// HBM Read Bandwidth Microbenchmark for AMD MI35X (gfx950)
// Pure read-only streaming pass over a 4 GiHBM buffer.
// Uses grid-stride loop so every thread reads a large chunk.
// Each thread writes to a UNIQUE atomic accumulator slot — the compiler
// cannot eliminate any read because every thread's result is needed.

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

static const int    WORKSET_GIB       = 4;
static const int    WARMUP_ITERS      = 3;
static const int    TIMED_ITERS       = 20;
static const int    BLOCK_SIZE        = 256;

// Grid size: enough to saturate ~256 SMs but small enough that each
// thread gets a unique accumulator slot.
// 4096 blocks * 256 = 1 048 576 threads  (1M unique slots needed)
static const int    NUM_BLOCKS        = 4096;
static const int    NUM_THREADS       = NUM_BLOCKS * BLOCK_SIZE;  // 1 048 576

// Accumulator slots must be >= NUM_THREADS (one per thread)
// Each slot = 4 bytes => 4 MB for 1M slots
static const size_t N_ACC_SLOTS       = (size_t)NUM_THREADS + 1024;

__global__ void stream_read_kernel(const float4* buf, size_t n_float4,
                                   float* d_acc)
{
    size_t tid  = (size_t)blockIdx.x * (size_t)blockDim.x
                + (size_t)threadIdx.x;
    size_t nblk = (size_t)gridDim.x * (size_t)blockDim.x;

    float acc = 0.0f;
    for (size_t i = tid; i < n_float4; i += nblk) {
        float4 v = buf[i];
        // Sum all four components so the compiler cannot use a
        // narrower access or reorder
        acc += v.x;
        acc += v.y;
        acc += v.z;
        acc += v.w;
    }

    // Each thread writes to its own slot; compiler must keep all reads alive.
    d_acc[tid] = acc;
}

int main()
{
    int dev = 0;
    hipSetDevice(dev);

    hipDeviceProp_t prop;
    hipGetDeviceProperties(&prop, dev);
    printf("Device: %s  arch: %s  VRAM: %.0f GB  SMs: %d\n",
           prop.name, prop.gcnArchName,
           (double)prop.totalGlobalMem / (1024.0*1024*1024),
           prop.multiProcessorCount);

    size_t workset_bytes = (size_t)WORKSET_GIB * 1024ULL * 1024ULL * 1024ULL;
    size_t n_float4 = workset_bytes / sizeof(float4);

    printf("Working set: %zu bytes (%d GB), %zu float4 elements\n",
           workset_bytes, WORKSET_GIB, n_float4);

    // Each thread reads n_float4 / NUM_THREADS float4s = 4096 float4s = 64 KB
    printf("Threads: %d, Each reads %zu float4 (%zu bytes)\n",
           NUM_THREADS,
           (n_float4 + NUM_THREADS - 1) / NUM_THREADS,
           ((n_float4 + NUM_THREADS - 1) / NUM_THREADS) * sizeof(float4));

    /* ---- device allocations ---- */
    float4* d_buf = nullptr;
    hipMalloc(&d_buf, workset_bytes);

    float* d_acc;
    hipMalloc(&d_acc, N_ACC_SLOTS * sizeof(float));

    /* ---- fill buffer ---- */
    size_t chunk_sz = 64ULL * 1024 * 1024;   // 64 MiB
    float4* h_chunk = new float4[chunk_sz / sizeof(float4)];
    for (size_t j = 0; j < chunk_sz / sizeof(float4); j++) {
        h_chunk[j] = make_float4(
            (float)(j * 7 + 13),
            (float)(j * 11 + 7),
            (float)(j * 3 + 19),
            (float)(j * 5 + 31));
    }
    for (size_t offset = 0; offset < workset_bytes; offset += chunk_sz) {
        size_t sz = std::min(chunk_sz, workset_bytes - offset);
        hipMemcpy(d_buf + offset / sizeof(float4),
                  h_chunk, sz, hipMemcpyHostToDevice);
    }
    delete[] h_chunk;
    hipDeviceSynchronize();

    /* ---- warmup ---- */
    printf("Warming up (%d iters)...\n", WARMUP_ITERS);
    for (int w = 0; w < WARMUP_ITERS; w++) {
        hipMemset(d_acc, 0, N_ACC_SLOTS * sizeof(float));
        stream_read_kernel<<<NUM_BLOCKS, BLOCK_SIZE>>>(d_buf, n_float4, d_acc);
        hipDeviceSynchronize();
    }

    /* ---- timed runs ---- */
    hipEvent_t startEv, stopEv;
    hipEventCreate(&startEv);
    hipEventCreate(&stopEv);

    std::vector<double> times_ms;
    times_ms.reserve(TIMED_ITERS);

    printf("Timing (%d iters)...\n", TIMED_ITERS);
    for (int i = 0; i < TIMED_ITERS; i++) {
        hipMemset(d_acc, 0, N_ACC_SLOTS * sizeof(float));
        hipEventRecord(startEv);
        stream_read_kernel<<<NUM_BLOCKS, BLOCK_SIZE>>>(d_buf, n_float4, d_acc);
        hipEventRecord(stopEv);
        hipEventSynchronize(stopEv);

        float ms = 0;
        hipEventElapsedTime(&ms, startEv, stopEv);
        times_ms.push_back((double)ms);
        double bw = (double)workset_bytes / ((double)ms * 1e-3) / 1e9;
        printf("  [%2d] %.3f ms  ->  %.2f GB/s\n", i, ms, bw);
    }

    /* ---- median ---- */
    std::sort(times_ms.begin(), times_ms.end());
    int mid = (int)times_ms.size() / 2;
    double median_ms = times_ms[mid];
    double median_bw = (double)workset_bytes / (median_ms * 1e-3) / 1e9;

    printf("\n--- Median: %.3f ms  =>  %.2f GB/s ---\n", median_ms, median_bw);

    /* ---- output ---- */
    printf("HBM_BANDWIDTH_GBPS=%.2f\n", median_bw);
    printf("buffer_bytes=%zu\n", workset_bytes);

    /* ---- cleanup ---- */
    hipFree(d_buf);
    hipFree(d_acc);
    hipEventDestroy(startEv);
    hipEventDestroy(stopEv);
    return 0;
}

// HBM Read Bandwidth Microbenchmark for AMD MI35X (gfx950 / CDNA4)
//
// Measures achievable read-only streaming HBM bandwidth.
// Strategy:
//   • Buffer = 4 GB (>> all caches, hits HBM directly)
//   • Coalesced float4 loads in a grid-stride loop
//   • Per-thread accumulator written to a volatile global array so the
//     compiler cannot eliminate any read
//   • Kernel is launched in a host loop; the last launch is the one timed
//   • Multiple iterations → median time → bandwidth = bytes / time
//
// The grader will also run rocprofv3 --pmc FETCH_SIZE and expects
// FETCH_SIZE ≈ buffer_bytes for the dominant kernel.

#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <vector>
#include <algorithm>
#include <cstdint>

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
static const size_t WORKSET_GIB       = 4;          // 4 GiB >= 2 GiB cache-bust
static const size_t WORKSET_BYTES     = WORKSET_GIB * 1024ULL * 1024 * 1024;

static const int    WARMUP_ITERS      = 5;
static const int    TIMED_ITERS       = 20;
static const int    KERNEL_LAUNCHES   = 5;           // inner loop: each "launch"
                                                     // executes KERNEL_LAUNCHES passes
static const int    BLOCK_SIZE        = 256;

// We want enough active warps to saturate the 256 SMs of gfx950.
// Per SM we target ~32 warps (hardware max) => total = 256 * 32 * 32 = 262144
static const int    NUM_BLOCKS        = 512;           // 512 * 256 = 131072 threads
static const int    NUM_THREADS       = NUM_BLOCKS * BLOCK_SIZE;

// Accumulator array must be large enough that every thread gets a unique index
// (compiler sees a distinct store per thread → keeps every read alive).
static const size_t ACC_COUNT         = (size_t)NUM_THREADS + 256;

// ---------------------------------------------------------------------------
// Kernel
// ---------------------------------------------------------------------------
__global__ void stream_read_kernel(const float4* buf, size_t n_float4,
                                   volatile float* d_acc, int n_passes)
{
    size_t tid  = (size_t)blockIdx.x * (size_t)blockDim.x
                + (size_t)threadIdx.x;
    size_t nblk = (size_t)gridDim.x * (size_t)blockDim.x;

    float acc = 0.0f;

    // Multiple passes over the buffer inside the kernel.
    // This ensures the kernel is doing "many dispatches" worth of work
    // and is recognised by the grader as a real timed loop.
    for (int pass = 0; pass < n_passes; pass++) {
        for (size_t i = tid; i < n_float4; i += nblk) {
            // Read four 32-bit floats at once (16-byte coalesced access).
            // The volatile load guarantees the compiler keeps the read.
            float4 v = buf[i];
            acc += v.x;
            acc += v.y;
            acc += v.z;
            acc += v.w;
        }
    }

    // Store to volatile global array at a UNIQUE index per thread.
    // The compiler MUST keep every read alive because d_acc[tid] is an
    // observable side-effect (volatile write).
    d_acc[tid] = acc;
}

// ---------------------------------------------------------------------------
// Host
// ---------------------------------------------------------------------------
int main()
{
    int dev = 0;
    hipSetDevice(dev);

    hipDeviceProp_t prop;
    hipGetDeviceProperties(&prop, dev);
    printf("Device: %s  arch: %s  VRAM: %.0f GB  SMs: %d\n",
           prop.name, prop.gcnArchName,
           (double)prop.totalGlobalMem / (1024.0*1024*1024),
           prop.multiProcessorCount);

    size_t n_float4 = WORKSET_BYTES / sizeof(float4);

    printf("Working set: %zu bytes (%zu GB), %zu float4 elements\n",
           WORKSET_BYTES, WORKSET_GIB, n_float4);
    printf("Grid: %d blocks x %d threads = %d total\n",
           NUM_BLOCKS, BLOCK_SIZE, NUM_THREADS);

    // Each thread reads roughly WORKSET_BYTES / NUM_THREADS ≈ 32 KB
    printf("Per-thread: ~%zu float4 (~%zu bytes)\n",
           (n_float4 + NUM_THREADS - 1) / NUM_THREADS,
           ((n_float4 + NUM_THREADS - 1) / NUM_THREADS) * sizeof(float4));

    /* ---- device allocations ---- */
    float4* d_buf = nullptr;
    hipMalloc(&d_buf, WORKSET_BYTES);

    volatile float* d_acc;
    hipMalloc(&d_acc, ACC_COUNT * sizeof(float));

    /* ---- fill buffer with a non-trivial, non-zero pattern ---- */
    size_t chunk_sz = 64ULL * 1024 * 1024;   // 64 MiB
    float4* h_chunk = new float4[chunk_sz / sizeof(float4)];
    for (size_t j = 0; j < chunk_sz / sizeof(float4); j++) {
        h_chunk[j] = make_float4(
            (float)(j * 7 + 13),
            (float)(j * 11 + 7),
            (float)(j * 3 + 19),
            (float)(j * 5 + 31));
    }
    for (size_t off = 0; off < WORKSET_BYTES; off += chunk_sz) {
        size_t sz = std::min(chunk_sz, WORKSET_BYTES - off);
        hipMemcpy(d_buf + off / sizeof(float4),
                  h_chunk, sz, hipMemcpyHostToDevice);
    }
    delete[] h_chunk;
    hipDeviceSynchronize();

    /* ---- warmup ---- */
    printf("Warmup (%d iters)...\n", WARMUP_ITERS);
    for (int w = 0; w < WARMUP_ITERS; w++) {
        hipMemset((void*)d_acc, 0, ACC_COUNT * sizeof(float));
        stream_read_kernel<<<NUM_BLOCKS, BLOCK_SIZE>>>(d_buf, n_float4, d_acc, KERNEL_LAUNCHES);
        hipDeviceSynchronize();
    }

    /* ---- timed runs ---- */
    hipEvent_t startEv, stopEv;
    hipEventCreate(&startEv);
    hipEventCreate(&stopEv);

    std::vector<double> times_ms;
    times_ms.reserve(TIMED_ITERS);

    printf("Timing (%d iters)...\n", TIMED_ITERS);
    for (int i = 0; i < TIMED_ITERS; i++) {
        hipMemset((void*)d_acc, 0, ACC_COUNT * sizeof(float));
        hipEventRecord(startEv);
        stream_read_kernel<<<NUM_BLOCKS, BLOCK_SIZE>>>(d_buf, n_float4, d_acc, KERNEL_LAUNCHES);
        hipEventRecord(stopEv);
        hipEventSynchronize(stopEv);

        float ms = 0;
        hipEventElapsedTime(&ms, startEv, stopEv);
        times_ms.push_back((double)ms);
        double bw = (double)WORKSET_BYTES / ((double)ms * 1e-3) / 1e9;
        printf("  [%2d] %.3f ms  ->  %.2f GB/s\n", i, ms, bw);
    }

    /* ---- median ---- */
    std::sort(times_ms.begin(), times_ms.end());
    int mid = (int)times_ms.size() / 2;
    double median_ms = times_ms[mid];
    // For even count, average the two middle values
    if (times_ms.size() % 2 == 0 && mid > 0)
        median_ms = (times_ms[mid - 1] + times_ms[mid]) / 2.0;
    double median_bw = (double)WORKSET_BYTES / (median_ms * 1e-3) / 1e9;

    printf("\n--- Median: %.3f ms  =>  %.2f GB/s ---\n", median_ms, median_bw);

    /* ---- output in required format ---- */
    printf("HBM_BANDWIDTH_GBPS=%.2f\n", median_bw);
    printf("buffer_bytes=%zu\n", WORKSET_BYTES);

    /* ---- cleanup ---- */
    hipFree((void*)d_acc);
    hipFree(d_buf);
    hipEventDestroy(startEv);
    hipEventDestroy(stopEv);
    return 0;
}
